using NUnit.Framework;

namespace E2ETests;

/// <summary>
/// Full CRUD flow tests for primary resources: Customers, Products, Employees, Orders.
/// Each test creates, reads (detail), updates, and deletes a record.
/// </summary>
[TestFixture]
public class CrudFlowTests : NorthwindTestBase
{
    // =============================================
    // CUSTOMER CRUD FLOW
    // =============================================

    [Test]
    public async Task Customer_CreateReadUpdateDelete()
    {
        var uniqueName = $"Test Customer {Guid.NewGuid():N}".Substring(0, 30);

        // CREATE
        await Page.GotoAsync("/customers/create");
        await Page.FillAsync("input[name='CustomerName']", uniqueName);
        await Page.FillAsync("input[name='PrimaryContactFirstName']", "Test");
        await Page.FillAsync("input[name='PrimaryContactLastName']", "Contact");
        await Page.FillAsync("input[name='BusinessPhone']", "555-0100");
        await Page.FillAsync("input[name='City']", "Testville");
        await Page.FillAsync("input[name='State']", "TX");
        await Page.ClickAsync("button[type='submit']");

        // Should redirect to detail page
        await Expect(Page).ToHaveURLAsync(new System.Text.RegularExpressions.Regex("/customers/\\d+"));
        await Expect(Page.Locator("h1")).ToContainTextAsync(uniqueName);

        // READ - verify detail page has customer name
        var detailUrl = Page.Url;
        await Expect(Page.Locator("input[name='CustomerName']")).ToHaveValueAsync(uniqueName);

        // UPDATE
        var updatedName = uniqueName.Replace("Test Customer", "Updated Customer");
        await Page.FillAsync("input[name='CustomerName']", updatedName);
        await Page.FillAsync("input[name='City']", "UpdatedCity");
        await Page.ClickAsync("button[type='submit']:has-text('Save')");
        await Page.GotoAsync(detailUrl);
        await Expect(Page.Locator("input[name='CustomerName']")).ToHaveValueAsync(updatedName);

        // DELETE
        Page.Dialog += async (_, dialog) => await dialog.AcceptAsync();
        await Page.ClickAsync("button[type='submit']:has-text('Delete')");
        // After delete, redirected to customer list
        await Expect(Page).ToHaveURLAsync(new System.Text.RegularExpressions.Regex("/customers$"));
    }

