    [Test]
    public async Task Product_CreateReadUpdateDelete()
    {
        var code = $"TST{Guid.NewGuid():N}".Substring(0, 8).ToUpper();
        var name = $"Test Product {code}";

        // CREATE
        await Page.GotoAsync("/products/create");
        await Page.FillAsync("input[name='ProductCode']", code);
        await Page.FillAsync("input[name='ProductName']", name);
        await Page.FillAsync("input[name='UnitPrice']", "19.99");
        await Page.ClickAsync("button[type='submit']");

        // Should redirect to detail page
        await Expect(Page).ToHaveURLAsync(new System.Text.RegularExpressions.Regex("/products/\\d+"));
        await Expect(Page.Locator("h1")).ToContainTextAsync(name);

        var detailUrl = Page.Url;

        // READ - verify fields
        await Expect(Page.Locator("input[name='ProductName']")).ToHaveValueAsync(name);
        await Expect(Page.Locator("input[name='ProductCode']")).ToHaveValueAsync(code);

        // UPDATE
        var updatedName = name + " Updated";
        await Page.FillAsync("input[name='ProductName']", updatedName);
        await Page.FillAsync("input[name='UnitPrice']", "24.99");
        await Page.ClickAsync("button[type='submit']:has-text('Save')");
        await Page.GotoAsync(detailUrl);
        await Expect(Page.Locator("input[name='ProductName']")).ToHaveValueAsync(updatedName);

        // DELETE
        Page.Dialog += async (_, dialog) => await dialog.AcceptAsync();
        await Page.ClickAsync("button[type='submit']:has-text('Delete')");
        await Expect(Page).ToHaveURLAsync(new System.Text.RegularExpressions.Regex("/products$"));
    }

