    // =============================================
    // ORDER CRUD FLOW
    // =============================================

    [Test]
    public async Task Order_CreateReadUpdateDelete()
    {
        // CREATE - navigate to create form
        await Page.GotoAsync("/orders/create");
        await Expect(Page.Locator("h1")).ToContainTextAsync("New Order");

        // Select first available customer (if any)
        var customerOptions = Page.Locator("select[name='CustomerId'] option:not([value=''])");
        if (await customerOptions.CountAsync() > 0)
        {
            var firstValue = await customerOptions.First.GetAttributeAsync("value");
            await Page.SelectOptionAsync("select[name='CustomerId']", firstValue ?? "");
        }

        // Select first available employee (if any)
        var employeeOptions = Page.Locator("select[name='EmployeeId'] option:not([value=''])");
        if (await employeeOptions.CountAsync() > 0)
        {
            var firstValue = await employeeOptions.First.GetAttributeAsync("value");
            await Page.SelectOptionAsync("select[name='EmployeeId']", firstValue ?? "");
        }

        // Set order date
        await Page.FillAsync("input[name='OrderDate']", DateTime.Today.ToString("yyyy-MM-dd"));
        await Page.FillAsync("textarea[name='Notes']", "E2E test order - can be deleted");
        await Page.ClickAsync("button[type='submit']");

        // Should redirect to order detail page
        await Expect(Page).ToHaveURLAsync(new System.Text.RegularExpressions.Regex("/orders/\\d+"));
        await Expect(Page.Locator("h1")).ToContainTextAsync("Order #");

        var detailUrl = Page.Url;

        // UPDATE - change notes
        await Page.FillAsync("textarea[name='Notes']", "E2E test order - updated");
        await Page.ClickAsync("button[type='submit']:has-text('Save Order')");

        // Reload and verify
        await Page.GotoAsync(detailUrl);
        await Expect(Page.Locator("textarea[name='Notes']")).ToHaveValueAsync("E2E test order - updated");

        // DELETE
        Page.Dialog += async (_, dialog) => await dialog.AcceptAsync();
        await Page.ClickAsync("button[type='submit']:has-text('Delete')");
        await Expect(Page).ToHaveURLAsync(new System.Text.RegularExpressions.Regex("/orders$"));
    }

    // =============================================
    // ORDERS LIST FILTER
    // =============================================

    [Test]
    public async Task Orders_FilterByStatus()
    {
        await Page.GotoAsync("/orders");

        // Find the status dropdown
        var statusSelect = Page.Locator("select[name='statusId']");
        await Expect(statusSelect).ToBeVisibleAsync();

        // Select first non-empty status option
        var options = statusSelect.Locator("option:not([value=''])");
        if (await options.CountAsync() > 0)
        {
            var firstValue = await options.First.GetAttributeAsync("value");
            await Page.SelectOptionAsync("select[name='statusId']", firstValue ?? "");
            await Page.ClickAsync("button[type='submit']:has-text('Filter')");
            // Page should reload with filter applied
            await Expect(Page).ToHaveURLAsync(new System.Text.RegularExpressions.Regex("statusId="));
        }
    }

